package com.example.recipetracker;

import android.content.Intent;
import android.os.Bundle;
import android.text.Editable;
import android.text.TextWatcher;
import android.widget.EditText;

import androidx.appcompat.app.AppCompatActivity;
import androidx.recyclerview.widget.GridLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.example.recipetracker.database.RecipeDatabase;
import com.google.android.material.bottomnavigation.BottomNavigationView;
import com.google.android.material.floatingactionbutton.FloatingActionButton;

/**
 * MainActivity — Home Screen
 *
 * What to build here:
 *  - RecyclerView grid of recipe cards
 *  - Search bar that filters results live
 *  - FAB to go to AddEditRecipeActivity
 *  - Bottom navigation (same on every screen)
 */
public class MainActivity extends AppCompatActivity {

    private RecyclerView recyclerView;
    private EditText searchBar;
    private FloatingActionButton fabAdd;
    private BottomNavigationView bottomNav;

    // TODO: create a RecipeAdapter class for the RecyclerView
    // private RecipeAdapter adapter;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        // Wire up views
        recyclerView = findViewById(R.id.recycler_recipes);
        searchBar    = findViewById(R.id.edit_search);
        fabAdd       = findViewById(R.id.fab_add_recipe);
        bottomNav    = findViewById(R.id.bottom_navigation);

        // Grid: 2 columns
        recyclerView.setLayoutManager(new GridLayoutManager(this, 2));

        // TODO: Set up adapter and attach to recyclerView

        // Load all recipes from DB and show them
        RecipeDatabase.getInstance(this)
                .recipeDao()
                .getAllRecipes()
                .observe(this, recipes -> {
                    // TODO: adapter.setRecipes(recipes);
                });

        // Live search — fires every time the user types
        searchBar.addTextChangedListener(new TextWatcher() {
            @Override public void beforeTextChanged(CharSequence s, int start, int count, int after) {}
            @Override public void onTextChanged(CharSequence s, int start, int before, int count) {
                String query = s.toString().trim();
                RecipeDatabase.getInstance(MainActivity.this)
                        .recipeDao()
                        .searchRecipes(query)
                        .observe(MainActivity.this, recipes -> {
                            // TODO: adapter.setRecipes(recipes);
                        });
            }
            @Override public void afterTextChanged(Editable s) {}
        });

        // FAB → Add recipe screen
        fabAdd.setOnClickListener(v -> {
            Intent intent = new Intent(this, AddEditRecipeActivity.class);
            startActivity(intent);
        });

        // Bottom nav
        setupBottomNav();
    }

    private void setupBottomNav() {
        bottomNav.setSelectedItemId(R.id.nav_home);
        bottomNav.setOnItemSelectedListener(item -> {
            int id = item.getItemId();
            if (id == R.id.nav_home) {
                return true; // already here
            } else if (id == R.id.nav_discover) {
                startActivity(new Intent(this, DiscoverActivity.class));
                overridePendingTransition(0, 0);
                return true;
            } else if (id == R.id.nav_favourites) {
                startActivity(new Intent(this, FavouritesActivity.class));
                overridePendingTransition(0, 0);
                return true;
            }
            return false;
        });
    }
}

package com.example.recipetracker;

import android.content.Intent;
import android.os.Bundle;
import android.text.Editable;
import android.text.TextWatcher;
import android.view.View;
import android.widget.LinearLayout;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;
import androidx.recyclerview.widget.GridLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.example.recipetracker.database.RecipeDatabase;
import com.google.android.material.bottomnavigation.BottomNavigationView;
import com.google.android.material.floatingactionbutton.FloatingActionButton;
import com.google.android.material.textfield.TextInputEditText;

import java.util.Calendar;

/**
 * MainActivity — Home Screen
 *
 * What to build here:
 *  - RecyclerView grid of recipe cards
 *  - Search bar that filters results live
 *  - FAB to go to AddEditRecipeActivity
 *  - Bottom navigation (same on every screen)
 *  - Dynamic greeting based on time of day
 *  - Empty state when no recipes exist
 */
public class MainActivity extends AppCompatActivity {

    private RecyclerView recyclerView;
    private TextInputEditText searchBar;
    private FloatingActionButton fabAdd;
    private BottomNavigationView bottomNav;
    private LinearLayout emptyStateContainer;
    private TextView greetingText;

    // TODO: create a RecipeAdapter class for the RecyclerView
    // private RecipeAdapter adapter;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        // Wire up views
        recyclerView = findViewById(R.id.recycler_recipes);
        searchBar = findViewById(R.id.edit_search);
        fabAdd = findViewById(R.id.fab_add_recipe);
        bottomNav = findViewById(R.id.bottom_navigation);
        emptyStateContainer = findViewById(R.id.empty_state_container);
        greetingText = findViewById(R.id.tv_greeting);

        // Set dynamic greeting based on time of day
        setDynamicGreeting();

        // Grid: 2 columns
        recyclerView.setLayoutManager(new GridLayoutManager(this, 2));

        // TODO: Set up adapter and attach to recyclerView

        // Load all recipes from DB and show them
        RecipeDatabase.getInstance(this)
                .recipeDao()
                .getAllRecipes()
                .observe(this, recipes -> {
                    // TODO: adapter.setRecipes(recipes);
                    updateEmptyState(recipes != null && !recipes.isEmpty());
                });

        // Live search — fires every time the user types
        searchBar.addTextChangedListener(new TextWatcher() {
            @Override public void beforeTextChanged(CharSequence s, int start, int count, int after) {}
            @Override public void onTextChanged(CharSequence s, int start, int before, int count) {
                String query = s.toString().trim();
                if (query.isEmpty()) {
                    // Show all recipes
                    RecipeDatabase.getInstance(MainActivity.this)
                            .recipeDao()
                            .getAllRecipes()
                            .observe(MainActivity.this, recipes -> {
                                // TODO: adapter.setRecipes(recipes);
                                updateEmptyState(recipes != null && !recipes.isEmpty());
                            });
                } else {
                    // Search recipes
                    RecipeDatabase.getInstance(MainActivity.this)
                            .recipeDao()
                            .searchRecipes(query)
                            .observe(MainActivity.this, recipes -> {
                                // TODO: adapter.setRecipes(recipes);
                                updateEmptyState(recipes != null && !recipes.isEmpty());
                            });
                }
            }
            @Override public void afterTextChanged(Editable s) {}
        });

        // FAB → Add recipe screen
        fabAdd.setOnClickListener(v -> {
            Intent intent = new Intent(this, AddEditRecipeActivity.class);
            startActivity(intent);
        });

        // Bottom nav
        setupBottomNav();
    }

    /**
     * Set greeting text based on current time of day
     */
    private void setDynamicGreeting() {
        Calendar calendar = Calendar.getInstance();
        int hour = calendar.get(Calendar.HOUR_OF_DAY);

        int greetingResId;
        if (hour >= 5 && hour < 12) {
            greetingResId = R.string.home_greeting_morning;
        } else if (hour >= 12 && hour < 17) {
            greetingResId = R.string.home_greeting_afternoon;
        } else {
            greetingResId = R.string.home_greeting_evening;
        }

        greetingText.setText(greetingResId);
    }

    /**
     * Show/hide empty state based on whether recipes exist
     */
    private void updateEmptyState(boolean hasRecipes) {
        if (hasRecipes) {
            recyclerView.setVisibility(View.VISIBLE);
            emptyStateContainer.setVisibility(View.GONE);
        } else {
            recyclerView.setVisibility(View.GONE);
            emptyStateContainer.setVisibility(View.VISIBLE);
        }
    }

    private void setupBottomNav() {
        bottomNav.setSelectedItemId(R.id.nav_home);
        bottomNav.setOnItemSelectedListener(item -> {
            int id = item.getItemId();
            if (id == R.id.nav_home) {
                return true; // already here
            } else if (id == R.id.nav_discover) {
                startActivity(new Intent(this, DiscoverActivity.class));
                overridePendingTransition(0, 0);
                return true;
            } else if (id == R.id.nav_favourites) {
                startActivity(new Intent(this, FavouritesActivity.class));
                overridePendingTransition(0, 0);
                return true;
            }
            return false;
        });
    }
}

package com.example.recipetracker.database;

import androidx.room.ColumnInfo;
import androidx.room.Entity;
import androidx.room.PrimaryKey;

/**
 * Recipe entity — represents a single recipe in the database
 */
@Entity(tableName = "recipes")
public class Recipe {
    @PrimaryKey(autoGenerate = true)
    public int id;

    @ColumnInfo(name = "title")
    public String title;

    @ColumnInfo(name = "ingredients")
    public String ingredients;

    @ColumnInfo(name = "steps")
    public String steps;

    @ColumnInfo(name = "category")
    public String category;

    @ColumnInfo(name = "prep_time")
    public String prepTime;

    @ColumnInfo(name = "created_by")
    public String createdBy;

    // Alias for compatibility
    public String addedByUser;

    @ColumnInfo(name = "is_favourite")
    public boolean isFavourite;

    @ColumnInfo(name = "created_at")
    public long createdAt;

    /**
     * Constructor for creating new recipes
     */
    public Recipe(String title, String ingredients, String steps, String category, String prepTime, String createdBy) {
        this.title = title;
        this.ingredients = ingredients;
        this.steps = steps;
        this.category = category;
        this.prepTime = prepTime;
        this.createdBy = createdBy;
        this.addedByUser = createdBy; // Alias for compatibility
        this.isFavourite = false;
        this.createdAt = System.currentTimeMillis();
    }

    @Override
    public String toString() {
        return "Recipe{" +
                "id=" + id +
                ", title='" + title + '\'' +
                ", category='" + category + '\'' +
                ", prepTime='" + prepTime + '\'' +
                '}';
    }
}

package com.example.recipetracker.database;

import androidx.lifecycle.LiveData;
import androidx.room.Dao;
import androidx.room.Delete;
import androidx.room.Insert;
import androidx.room.Query;
import androidx.room.Update;

import java.util.List;

/**
 * RecipeDao — Data Access Object for Recipe CRUD operations
 */
@Dao
public interface RecipeDao {

    /**
     * Insert a new recipe
     */
    @Insert
    void insert(Recipe recipe);

    /**
     * Update an existing recipe
     */
    @Update
    void update(Recipe recipe);

    /**
     * Delete a recipe
     */
    @Delete
    void delete(Recipe recipe);

    /**
     * Get recipe by ID
     */
    @Query("SELECT * FROM recipes WHERE id = :id LIMIT 1")
    Recipe getById(int id);

    /**
     * Get all recipes as LiveData
     */
    @Query("SELECT * FROM recipes ORDER BY created_at DESC")
    LiveData<List<Recipe>> getAllRecipes();

    /**
     * Search recipes by title, category, or ingredients
     */
    @Query("SELECT * FROM recipes WHERE title LIKE '%' || :query || '%' " +
            "OR category LIKE '%' || :query || '%' " +
            "OR ingredients LIKE '%' || :query || '%' " +
            "ORDER BY created_at DESC")
    LiveData<List<Recipe>> searchRecipes(String query);

    /**
     * Get all favourite recipes
     */
    @Query("SELECT * FROM recipes WHERE is_favourite = 1 ORDER BY created_at DESC")
    LiveData<List<Recipe>> getFavouriteRecipes();

    /**
     * Alternative method name for getFavouriteRecipes
     */
    @Query("SELECT * FROM recipes WHERE is_favourite = 1 ORDER BY created_at DESC")
    LiveData<List<Recipe>> getFavourites();

    /**
     * Get random recipes for discovery
     */
    @Query("SELECT * FROM recipes ORDER BY RANDOM() LIMIT 10")
    LiveData<List<Recipe>> getRandomRecipes();

    /**
     * Toggle favourite status
     */
    @Query("UPDATE recipes SET is_favourite = :isFavourite WHERE id = :recipeId")
    void setFavourite(int recipeId, boolean isFavourite);

    /**
     * Delete all recipes
     */
    @Query("DELETE FROM recipes")
    void deleteAll();
}

package com.example.recipetracker.database;

import android.content.Context;

import androidx.room.Database;
import androidx.room.Room;
import androidx.room.RoomDatabase;

/**
 * RecipeDatabase — Room database for storing recipes
 */
@Database(entities = {Recipe.class}, version = 1, exportSchema = false)
public abstract class RecipeDatabase extends RoomDatabase {

    public abstract RecipeDao recipeDao();

    private static volatile RecipeDatabase INSTANCE;

    /**
     * Get singleton database instance
     */
    public static RecipeDatabase getInstance(Context context) {
        if (INSTANCE == null) {
            synchronized (RecipeDatabase.class) {
                if (INSTANCE == null) {
                    INSTANCE = Room.databaseBuilder(
                            context.getApplicationContext(),
                            RecipeDatabase.class,
                            "recipe_database"
                    )
                    .fallbackToDestructiveMigration() // For development only
                    .build();
                }
            }
        }
        return INSTANCE;
    }
}

package com.example.recipetracker.util;

import android.content.Context;
import android.content.SharedPreferences;

/**
 * SessionManager — Manages user session data using SharedPreferences
 */
public class SessionManager {

    private static final String PREF_NAME = "recipe_tracker_session";
    private static final String KEY_USERNAME = "username";
    private static final String KEY_IS_LOGGED_IN = "is_logged_in";

    private final SharedPreferences sharedPreferences;
    private final SharedPreferences.Editor editor;

    public SessionManager(Context context) {
        sharedPreferences = context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE);
        editor = sharedPreferences.edit();
    }

    /**
     * Save user session
     */
    public void createSession(String username) {
        editor.putString(KEY_USERNAME, username);
        editor.putBoolean(KEY_IS_LOGGED_IN, true);
        editor.apply();
    }

    /**
     * Get current username
     */
    public String getUsername() {
        return sharedPreferences.getString(KEY_USERNAME, "User");
    }

    /**
     * Check if user is logged in
     */
    public boolean isLoggedIn() {
        return sharedPreferences.getBoolean(KEY_IS_LOGGED_IN, false);
    }

    /**
     * Logout user
     */
    public void logout() {
        editor.clear();
        editor.apply();
    }

    /**
     * Set default username if not set
     */
    public void ensureUsername() {
        if (getUsername().equals("User")) {
            createSession("User");
        }
    }
}
